//
// Firmware Management
package firmwareupdatestatus

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40032/idl"
)

// Firmware update status
type UpdateStatus struct {
	State         string // Current state of firmware update: NONE, INIT, PREP, SIMULATE, UPDATE, SUCCESS or FAIL
	Elapsed       int32  // Seconds since start of update, 0 if not available
	Estimated     int32  // Estimated total time for update, 0 if not available
	Error_message string // Error message; empty if there was no error
}

// Firmware update status interface.
//
// Unlike all other sysrpc methods this function is implemented by a
// CGI script which is available even during a firmware update. The
// URL for this interface is /cgi-bin/fwupdate_progress.cgi.
type FirmwareUpdateStatus interface {
	idl.Object

	// Returns the device's firmware update status.
	//
	//	@return Update status structure
	GetStatus(ctx context.Context) (UpdateStatus, error)
}
